import { neon, neonConfig } from "@neondatabase/serverless";

neonConfig.fetchEndpoint = (host) => `https://${host}/sql`;

const { DATABASE_HOST, DATABASE_USERNAME, DATABASE_PASSWORD } = process.env;
if (!DATABASE_HOST || !DATABASE_USERNAME || !DATABASE_PASSWORD) {
  console.error("Missing DB env vars");
  process.exit(1);
}

const sql = neon(
  `postgresql://${DATABASE_USERNAME}:${DATABASE_PASSWORD}@${DATABASE_HOST}/postgres?sslmode=require`,
);

const tableExists = await sql`
  SELECT EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'public' AND table_name = 'lightfast_github_org_bindings'
  ) AS exists
`;
console.log("lightfast_github_org_bindings exists:", tableExists[0].exists);

const drizzleTables = await sql`
  SELECT table_schema, table_name FROM information_schema.tables
  WHERE table_name LIKE '%drizzle%' OR table_name ILIKE '%migration%'
  ORDER BY table_schema, table_name
`;
console.log("drizzle/migration tables:", drizzleTables);

for (const { table_schema, table_name } of drizzleTables) {
  const rows = await sql(
    `SELECT * FROM "${table_schema}"."${table_name}" ORDER BY 1 DESC LIMIT 5`,
  );
  console.log(`\n${table_schema}.${table_name} (last 5 rows):`, rows);
}

